import { mkdir, writeFile } from "node:fs/promises";
import path from "node:path";

export function createTsHeader(generatedBy: string): string {
  return `/**
 * Generated by ${generatedBy}.
 * Do not edit by hand; update the contract/template instead.
 */

`;
}

export function getRelativeImportPath(fromDir: string, targetPath: string): string {
  const relativePath = toPortablePath(path.relative(fromDir, targetPath));
  return relativePath.startsWith(".") ? relativePath : `./${relativePath}`;
}

export function renderTsValue(value: unknown, indent = 0): string {
  const space = " ".repeat(indent);
  const nextIndent = indent + 2;
  const nextSpace = " ".repeat(nextIndent);

  if (Array.isArray(value)) {
    if (value.length === 0) return "[]";
    return `[\n${value.map((item) => `${nextSpace}${renderTsValue(item, nextIndent)},`).join("\n")}\n${space}]`;
  }

  if (value && typeof value === "object") {
    const entries = Object.entries(value);
    if (entries.length === 0) return "{}";

    return `{\n${entries
      .map(
        ([key, entryValue]) =>
          `${nextSpace}${formatObjectKey(key)}: ${renderTsValue(entryValue, nextIndent)},`,
      )
      .join("\n")}\n${space}}`;
  }

  return JSON.stringify(value);
}

export function toPortablePath(value: string): string {
  return value.split(path.sep).join("/");
}

export async function writeGeneratedFile(
  dir: string,
  fileName: string,
  contents: string,
): Promise<void> {
  await mkdir(dir, { recursive: true });
  await writeFile(path.join(dir, fileName), `${contents.trimEnd()}\n`);
}

function formatObjectKey(key: string): string {
  return /^[A-Za-z_$][\w$]*$/.test(key) ? key : JSON.stringify(key);
}
